changeSet.sql:
DROP TABLE IF EXISTS ads CASCADE;
DROP TABLE IF EXISTS ad_sets CASCADE;
DROP TABLE IF EXISTS campaigns CASCADE;
DROP TABLE IF EXISTS ad CASCADE;
DROP TABLE IF EXISTS ad_set CASCADE;

CREATE TABLE campaign (
    id              BIGSERIAL PRIMARY KEY,
    user_id         BIGINT        NOT NULL,
    external_id     VARCHAR(64)   NOT NULL,
    name            VARCHAR(255)  NOT NULL,
    status          VARCHAR(32)   NOT NULL,
    platform        VARCHAR(32)   NOT NULL,
    ad_account_id   VARCHAR(64)   NOT NULL,
    created_at      TIMESTAMP,
    updated_at      TIMESTAMP,
    CONSTRAINT fk_campaign_user
        FOREIGN KEY (user_id) REFERENCES users(id),
    CONSTRAINT uq_campaign_user_platform_account_ext
        UNIQUE (user_id, platform, ad_account_id, external_id)
);
